command:
// =========================
// DISTANT HEX SCOUT GENERATOR
// "What might be there?"
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

const featureTable = [
    { min: 1, max: 3, result: "Landmark" },
{ min: 4, max: 4, result: "Settlement" },
{ min: 5, max: 5, result: "Lair" },
{ min: 6, max: 6, result: "Dungeon" }
];

const settlementTable = [
    { roll: 1, result: "Hamlet" },
{ roll: 2, result: "Village" },
{ roll: 3, result: "City" },
{ roll: 4, result: "Castle" },
{ roll: 5, result: "Tower" },
{ roll: 6, result: "Abbey" }
];

const featureRoll = roll(6);
const feature = tableRoll(featureRoll, featureTable).result;

let output = `
<h2>Distant Hex Scout</h2>

<p><i>You are too far away to see details, but you can make out the general shape of something in the hex.</i></p>

<hr>

<p><b>Feature Roll:</b> d6 = ${featureRoll}</p>
<p><b>Visible Feature:</b> ${feature}</p>
`;

if (feature === "Settlement") {
    const settlementRoll = roll(6);
    const settlement = settlementTable.find(s => s.roll === settlementRoll).result;

    output += `
    <hr>
    <p><b>Settlement Type Roll:</b> d6 = ${settlementRoll}</p>
    <p><b>Visible Settlement Type:</b> ${settlement}</p>
    `;
}

output += `
<hr>

<h3>Scout Summary</h3>
<p>
From a distance, this hex appears to contain:
<b>${feature === "Settlement" ? "a settlement" : "a " + feature.toLowerCase()}</b>.
</p>
`;

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
